    "start_angle" NUMERIC NOT NULL,
    "end_angle" NUMERIC NOT NULL,
    "fill_color" CHARACTER VARYING(20) DEFAULT '#00FF00'::character varying,
    "stroke_color" CHARACTER VARYING(20) DEFAULT '#000000'::character varying,
    "name" CHARACTER VARYING(255),
    "created_by" INTEGER,
    "created_at" TIMESTAMP WITHOUT TIME ZONE DEFAULT CURRENT_TIMESTAMP,
    PRIMARY KEY ("id")
);

-- Table: sector_rf_data
CREATE TABLE IF NOT EXISTS "sector_rf_data" (
    "id" SERIAL NOT NULL,
    "user_id" INTEGER NOT NULL,
    "region_id" INTEGER,
    "sector_name" CHARACTER VARYING(255),
    "created_at" TIMESTAMP WITHOUT TIME ZONE DEFAULT CURRENT_TIMESTAMP,
    "tower_lat" NUMERIC NOT NULL,
    "tower_lng" NUMERIC NOT NULL,
    "azimuth" NUMERIC NOT NULL,
    "beamwidth" NUMERIC DEFAULT 65.00,
    "radius" NUMERIC DEFAULT 1000.00,
    "frequency" NUMERIC,
    "power" NUMERIC,
    "antenna_height" NUMERIC,
    "antenna_type" CHARACTER VARYING(100),
    "fill_color" CHARACTER VARYING(20) DEFAULT '#ff6b6b'::character varying,
    "stroke_color" CHARACTER VARYING(20) DEFAULT '#ff6b6b'::character varying,
    "opacity" NUMERIC DEFAULT 0.40,
    "properties" JSONB,
    "notes" TEXT,
    "is_saved" INTEGER DEFAULT 0,
    PRIMARY KEY ("id")
);

-- Table: spatial_ref_sys
CREATE TABLE IF NOT EXISTS "spatial_ref_sys" (
    "srid" INTEGER NOT NULL,
    "auth_name" CHARACTER VARYING(256),
    "auth_srid" INTEGER,
    "srtext" CHARACTER VARYING(2048),
    "proj4text" CHARACTER VARYING(2048),
    PRIMARY KEY ("srid")
);

-- Table: temporary_access_log
CREATE TABLE IF NOT EXISTS "temporary_access_log" (
    "id" SERIAL NOT NULL,
    "user_id" INTEGER NOT NULL,
    "granted_by" INTEGER NOT NULL,
    "region_id" INTEGER,
    "start_time" TIMESTAMP WITHOUT TIME ZONE DEFAULT CURRENT_TIMESTAMP,
    "end_time" TIMESTAMP WITHOUT TIME ZONE NOT NULL,
    "reason" TEXT,
    "status" CHARACTER VARYING(50) DEFAULT 'active'::character varying,
    "revoked_at" TIMESTAMP WITHOUT TIME ZONE,
    "revoked_by" INTEGER,
    PRIMARY KEY ("id")
);

