-- Table: user_permissions
CREATE TABLE IF NOT EXISTS "user_permissions" (
    "id" SERIAL NOT NULL,
    "user_id" INTEGER NOT NULL,
    "permission_id" CHARACTER VARYING(100) NOT NULL,
    "granted_by" INTEGER NOT NULL,
    "granted_at" TIMESTAMP WITHOUT TIME ZONE DEFAULT CURRENT_TIMESTAMP,
    PRIMARY KEY ("id")
);

-- Table: user_regions
CREATE TABLE IF NOT EXISTS "user_regions" (
    "id" SERIAL NOT NULL,
    "user_id" INTEGER NOT NULL,
    "region_id" INTEGER NOT NULL,
    "access_level" CHARACTER VARYING(50) DEFAULT 'read'::character varying,
    "assigned_at" TIMESTAMP WITHOUT TIME ZONE DEFAULT CURRENT_TIMESTAMP,
    "assigned_by" INTEGER,
    PRIMARY KEY ("id")
);

-- Table: user_sessions
CREATE TABLE IF NOT EXISTS "user_sessions" (
    "id" SERIAL NOT NULL,
    "session_token" CHARACTER VARYING(255),
    "user_id" INTEGER NOT NULL,
    "token" CHARACTER VARYING(500) NOT NULL,
    "ip_address" CHARACTER VARYING(45),
    "user_agent" TEXT,
    "created_at" TIMESTAMP WITHOUT TIME ZONE DEFAULT CURRENT_TIMESTAMP,
    "expires_at" TIMESTAMP WITHOUT TIME ZONE NOT NULL,
    "logout_time" TIMESTAMP WITHOUT TIME ZONE,
    "logout_type" CHARACTER VARYING(20),
    "last_activity" TIMESTAMP WITHOUT TIME ZONE DEFAULT CURRENT_TIMESTAMP,
    PRIMARY KEY ("id")
);

-- Table: user_settings
CREATE TABLE IF NOT EXISTS "user_settings" (
    "user_id" INTEGER NOT NULL,
    "settings_json" JSONB,
    "updated_at" TIMESTAMP WITHOUT TIME ZONE DEFAULT CURRENT_TIMESTAMP,
    "created_at" TIMESTAMP WITHOUT TIME ZONE DEFAULT CURRENT_TIMESTAMP,
    PRIMARY KEY ("user_id")
);

-- Table: users
CREATE TABLE IF NOT EXISTS "users" (
    "id" SERIAL NOT NULL,
    "email" CHARACTER VARYING(255) NOT NULL,
    "password" CHARACTER VARYING(255),
    "password_hash" CHARACTER VARYING(255),
    "username" CHARACTER VARYING(100) NOT NULL,
    "full_name" CHARACTER VARYING(255),
    "phone" CHARACTER VARYING(20),
    "department" CHARACTER VARYING(100),
    "office_location" CHARACTER VARYING(255),
    "gender" CHARACTER VARYING(50),
    "street" CHARACTER VARYING(255),
    "city" CHARACTER VARYING(100),
    "state" CHARACTER VARYING(100),
    "pincode" CHARACTER VARYING(10),
    "role" CHARACTER VARYING(50) DEFAULT 'user'::character varying,
    "is_verified" INTEGER DEFAULT 0,
    "is_active" BOOLEAN DEFAULT true,
    "is_email_verified" BOOLEAN DEFAULT false,
    "email_verified_at" TIMESTAMP WITHOUT TIME ZONE,
    "email_verified_by" INTEGER,
    "manual_verification" INTEGER DEFAULT 0,
    "last_verification_email_sent" TIMESTAMP WITHOUT TIME ZONE,
    "verification_token" CHARACTER VARYING(255),
    "verification_token_expires" TIMESTAMP WITHOUT TIME ZONE,
    "mfa_enabled" INTEGER DEFAULT 0,
    "mfa_method" CHARACTER VARYING(50) DEFAULT 'email'::character varying,
    "mfa_enabled_at" TIMESTAMP WITHOUT TIME ZONE,
    "is_online" BOOLEAN DEFAULT false,
    "created_by" INTEGER,
    "created_at" TIMESTAMP WITHOUT TIME ZONE DEFAULT CURRENT_TIMESTAMP,
    "updated_at" TIMESTAMP WITHOUT TIME ZONE DEFAULT CURRENT_TIMESTAMP,
    "last_login" TIMESTAMP WITHOUT TIME ZONE,
    "map_preferences" JSONB DEFAULT '{}'::jsonb,
    PRIMARY KEY ("id")
);


