-- New Project/File System Schema
CREATE TABLE IF NOT EXISTS "project_folders" (
    "id" UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    "name" VARCHAR(255) NOT NULL,
    "parent_id" UUID REFERENCES "project_folders" ("id") ON DELETE CASCADE,
    "path" TEXT NOT NULL,
    "created_at" TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP,
    "updated_at" TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE IF NOT EXISTS "project_files" (
    "id" UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    "folder_id" UUID REFERENCES "project_folders" ("id") ON DELETE CASCADE,
    "name" VARCHAR(255) NOT NULL,
    "type" VARCHAR(50) NOT NULL,
    "size_bytes" BIGINT,
    "storage_path" TEXT NOT NULL,
    "metadata" JSONB,
    "is_visible" BOOLEAN DEFAULT true,
    "imported_at" TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP,
    "imported_by" INTEGER
);

CREATE TABLE IF NOT EXISTS "project_features" (
    "id" UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    "file_id" UUID REFERENCES "project_files" ("id") ON DELETE CASCADE,
    "feature_type" VARCHAR(50),
    "properties" JSONB,
    "geom" GEOMETRY(Geometry, 4326),
    "created_at" TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP
);

CREATE INDEX IF NOT EXISTS idx_project_features_geom ON "project_features" USING GIST ("geom");
CREATE INDEX IF NOT EXISTS idx_project_features_properties ON "project_features" USING GIN ("properties");
